def min_leftover_chars(s: str, words: list[str]) -> int:
    def helper(s: str, words: list[str], memo={}) -> int:
        if s in memo:
            return memo[s]
        if not s:
            return 0

        min_leftovers = len(s)

        for i in range(1, len(s) + 1):
            if s[:i] in words:
                leftovers = helper(s[i:], words)
                min_leftovers = min(min_leftovers, leftovers)

